static uint32_t encode_utf32(uint32_t first, uint32_t last, uint32_t* s) {
	uint32_t* const s0 = s;
	for (uint32_t i = first; i <= last; ++i) *s++ = i;
	for (uint32_t i = 0; i < 1; ++i) *s++ = (first == 0) ? 0xFFFFffff : 0;
	return s - s0;
}

